class Solution {
    public int numberOfSubstrings(String s) {
        int res = 0, a = -1, b = -1, c = -1;
        for (int i = 0; i < s.length(); i++) {
            if (s.charAt(i) == 'a') a = i;
            if (s.charAt(i) == 'b') b = i;
            if (s.charAt(i) == 'c') c = i;
            res += Math.min(Math.min(a, b), Math.min(b, c)) + 1;
        }
        return res;
    }
}
